mapper.select:
SELECT * FROM (
    SELECT a.*, ROWNUM AS rn FROM (
        SELECT USER_NO as userNo, USER_NAME as userName, EMAIL as email,
               PHONE as phone, REG_DATE as regDate, STATUS as status,
               IDLE as idle, SUSPENDED as suspended, MANNER_TEMP as mannerTemp
        FROM MEMBER
        ORDER BY REG_DATE DESC
    ) a WHERE ROWNUM <= #{end}
) WHERE rn > #{start}

SELECT *
FROM ADS
WHERE STATUS = 'CONFIRM'
AND START_DATE <= #{endDate}
AND END_DATE <= #{startDate}
AND AD_ID != #{adId}

SELECT * FROM ( SELECT a.*, ROWNUM AS rn FROM ( SELECT r.REVIEW_NO as reviewNo, m.EMAIL as email, m.NICKNAME as nickname, r.RATING as rating, r.REVIEW_CONTENT as reviewContent, r.ONE_LINE_CAT as oneLineCat, r.CREATED_AT as createdAt, 0 as flagged FROM REVIEWS r JOIN MEMBER m ON r.EMAIL = m.EMAIL
WHERE (LOWER(m.NICKNAME) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(r.REVIEW_CONTENT) LIKE '%' || LOWER(#{keyword}) || '%')
ORDER BY r.CREATED_AT DESC ) a WHERE ROWNUM <= #{end} ) WHERE rn > #{start}

SELECT * FROM (
    SELECT a.*, ROWNUM AS rn FROM (
        SELECT r.REPORT_ID      as reportId,
               r.REPORTER_EMAIL as reporterEmail,
               r.TARGET_EMAIL   as targetEmail,
               rt.TYPE_NAME     as typeName,
               rt.MAIN_CATEGORY as mainCategory,
               r.REPORT_DETAIL  as reportDetail,
               r.REPORT_DATE    as reportDate,
               r.REPORT_STATUS  as reportStatus
        FROM REPORTS r
        JOIN REPORT_TYPES rt ON r.TYPE_ID = rt.TYPE_ID

        WHERE rt.MAIN_CATEGORY = #{type}

        ORDER BY r.REPORT_DATE DESC
    ) a WHERE ROWNUM <= #{end}
) WHERE rn > #{start}

SELECT COUNT(*) FROM REPORTS r
JOIN REPORT_TYPES rt ON r.TYPE_ID = rt.TYPE_ID

WHERE rt.MAIN_CATEGORY = #{type}

SELECT * FROM ( SELECT a.*, ROWNUM AS rn FROM ( SELECT INQUIRY_ID as inquiryId, MEMBER_EMAIL as memberEmail, TITLE as title, CONTENT as content, CREATED_AT as createdAt, INQUIRY_STATUS as inquiryStatus, ADMIN_ANSWER as adminAnswer, ANSWERED_AT as answeredAt, IS_FAQ as isFaq, IS_PRIVATE as isPrivate FROM INQUIRIES WHERE IS_FAQ = 'N'
AND INQUIRY_STATUS = #{status}
ORDER BY CREATED_AT DESC ) a WHERE ROWNUM <= #{end} ) WHERE rn > #{start}

SELECT COUNT(*) FROM INQUIRIES
WHERE IS_FAQ = 'N'

  AND INQUIRY_STATUS = #{status}

SELECT IMG_URL FROM PRODUCT_IMAGE
WHERE PRODUCT_NO = #{productNo}
ORDER BY SORT_NO ASC
